const logWarn = (message) => {
  console.warn("\x1B[33mQwik Speak warn\x1B[0m %s", message);
};
const logDebug = (enabled, message) => {
  if (enabled)
    console.debug("\x1B[36mQwik Speak\x1B[0m %s", message);
};
const logDebugInline = (enabled, ...data) => {
  if (enabled)
    console.debug("%cQwik Speak Inline", "background: #0c75d2; color: white; padding: 2px 3px; border-radius: 2px; font-size: 0.8em;", ...data);
};
export {
  logDebug,
  logDebugInline,
  logWarn
};
